     1|/**
     2| * live-evidence.ts — End-to-end deployment evidence checker for IVX.
     3| *
     4| * Hardened edition with:
     5| *   - Auto-refresh state tracking (LIVE / STALE / FAILED)
     6| *   - Commit match (GitHub vs Render vs /health)
     7| *   - Render deploy history (last N deploys)
     8| *   - Health metrics (response time, uptime, error rate, last failed)
     9| *   - Chat proof with message-id persistence verification
    10| *   - Supabase proof with RLS/auth status
    11| *   - Evidence history persistence (AsyncStorage)
    12| *   - Export helpers (JSON string, clipboard-ready report)
    13| *
    14| * Orchestrates all evidence tool checks and returns a structured
    15| * LiveEvidenceReport with individual tool results plus an aggregated
    16| * FINAL_STATUS.
    17| */
    18|
    19|import AsyncStorage from '@react-native-async-storage/async-storage';
