   157|// ---------------------------------------------------------------------------
   158|// Constants
   159|// ---------------------------------------------------------------------------
   160|
   161|const API_BASE = getDirectApiBaseUrl();
   162|const EVIDENCE_HISTORY_KEY = 'ivx_evidence_history';
   163|const MAX_HISTORY_ENTRIES = 50;
   164|const STALE_THRESHOLD_MS = 120_000; // 2 minutes
   165|
   166|// ---------------------------------------------------------------------------
   167|// Helpers
   168|// ---------------------------------------------------------------------------
   169|
   170|function generateId(): string {
   171|  return `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
   172|}
   173|
   174|function parseError(err: unknown): string {
   175|  if (err instanceof Error) return err.message;
   176|  return String(err ?? 'Unknown error');
   177|}
   178|
   179|async function fetchJSON(
   180|  url: string,
   181|  options: RequestInit = {},
   182|): Promise<{ ok: boolean; data: Record<string, unknown>; status: number; elapsedMs: number; error: string }> {
   183|  const start = performance.now();
   184|  try {
   185|    const response = await fetch(url, {
   186|      ...options,
   187|      headers: {
   188|        'Content-Type': 'application/json',
   189|        ...(options.headers as Record<string, string>),
   190|      },
   191|    });
   192|    const elapsedMs = Math.round(performance.now() - start);
   193|    const text = await response.text();
   194|    let data: Record<string, unknown> = {};
   195|    try {
   196|      data = JSON.parse(text);
   197|    } catch {
   198|      data = { raw: text.slice(0, 500) };
   199|    }
   200|    return {
   201|      ok: response.ok,
   202|      data,
   203|      status: response.status,
   204|      elapsedMs,
   205|      error: response.ok ? '' : (data.error as string) || `HTTP ${response.status}`,
   206|    };
   207|  } catch (err) {
   208|    return {
   209|      ok: false,
   210|      data: {},
   211|      status: 0,
   212|      elapsedMs: Math.round(performance.now() - start),
   213|      error: parseError(err),
   214|    };
   215|  }
   216|}
   217|
   218|function computeFreshness(timestamp: string): DataFreshness {
   219|  if (!timestamp) return 'FAILED';
   220|  const age = Date.now() - new Date(timestamp).getTime();
   221|  if (age < STALE_THRESHOLD_MS) return 'LIVE';
   222|  return 'STALE';
   223|}
