   228|
   229|export async function loadEvidenceHistory(): Promise<EvidenceHistoryEntry[]> {
   230|  try {
   231|    const raw = await AsyncStorage.getItem(EVIDENCE_HISTORY_KEY);
   232|    if (!raw) return [];
   233|    const parsed = JSON.parse(raw) as EvidenceHistoryEntry[];
   234|    return Array.isArray(parsed) ? parsed : [];
   235|  } catch {
   236|    return [];
   237|  }
   238|}
   239|
   240|export async function saveEvidenceHistoryEntry(entry: EvidenceHistoryEntry): Promise<void> {
   241|  try {
   242|    const history = await loadEvidenceHistory();
   243|    history.unshift(entry);
   244|    const trimmed = history.slice(0, MAX_HISTORY_ENTRIES);
   245|    await AsyncStorage.setItem(EVIDENCE_HISTORY_KEY, JSON.stringify(trimmed));
   246|  } catch (err) {
   247|    console.warn('[LiveEvidence] Failed to save history entry:', parseError(err));
   248|  }
   249|}
   250|
   251|export async function clearEvidenceHistory(): Promise<void> {
   252|  try {
   253|    await AsyncStorage.removeItem(EVIDENCE_HISTORY_KEY);
   254|  } catch (err) {
   255|    console.warn('[LiveEvidence] Failed to clear history:', parseError(err));
   256|  }
