   263|/** Fetches GitHub commit SHA from the live backend /version endpoint. */
   264|async function checkGitHubEvidence(
   265|  pushEvent: (event: StreamEvent) => void,
   266|): Promise<GitHubEvidenceResult> {
   267|  pushEvent({
   268|    id: generateId(),
   269|    tool: 'GitHub',
   270|    phase: 'started',
   271|    message: 'Fetching GitHub commit info from /version',
   272|    timestamp: new Date().toISOString(),
   273|  });
   274|
   275|  try {
   276|    const { ok, data, error } = await fetchJSON(`${API_BASE}/version`);
   277|
   278|    if (!ok) {
   279|      pushEvent({
   280|        id: generateId(),
   281|        tool: 'GitHub',
   282|        phase: 'error',
   283|        message: `GitHub check failed: ${error}`,
   284|        timestamp: new Date().toISOString(),
   285|        detail: error,
   286|      });
   287|      return {
   288|        status: 'fail',
   289|        repo: 'ibb142/rork-ivxholding--1',
   290|        branch: '',
   291|        latestCommitSha: '',
   292|        commitShort: '',
   293|        commitTimestamp: '',
   294|        error,
   295|      };
   296|    }
   297|
   298|    const result: GitHubEvidenceResult = {
   299|      status: 'ok',
   300|      repo: 'ibb142/rork-ivxholding--1',
   301|      branch: 'main',
   302|      latestCommitSha: (data.commit as string) || '',
   303|      commitShort: ((data.commitShort as string) || (data.commit as string) || '').slice(0, 8),
   304|      commitTimestamp: (data.bootTime as string) || (data.timestamp as string) || '',
   305|    };
   306|
   307|    pushEvent({
   308|      id: generateId(),
   309|      tool: 'GitHub',
   310|      phase: 'completed',
   311|      message: `GitHub commit: ${result.commitShort}`,
   312|      timestamp: new Date().toISOString(),
   313|      detail: result.latestCommitSha,
   314|    });
   315|
   316|    return result;
   317|  } catch (err) {
   318|    const msg = parseError(err);
