   320|      id: generateId(),
   321|      tool: 'GitHub',
   322|      phase: 'error',
   323|      message: `GitHub check exception: ${msg}`,
   324|      timestamp: new Date().toISOString(),
   325|      detail: msg,
   326|    });
   327|    return {
   328|      status: 'fail',
   329|      repo: 'ibb142/rork-ivxholding--1',
   330|      branch: '',
   331|      latestCommitSha: '',
