   339|/** Fetches Render deployment status and deploy history from the backend. */
   340|async function checkRenderEvidence(
   341|  pushEvent: (event: StreamEvent) => void,
   342|): Promise<RenderEvidenceResult> {
   343|  pushEvent({
   344|    id: generateId(),
   345|    tool: 'Render',
   346|    phase: 'started',
   347|    message: 'Fetching Render deployment status',
   348|    timestamp: new Date().toISOString(),
   349|  });
   350|
   351|  try {
   352|    // Try the render-status tool endpoint
   353|    const { ok, data, error } = await fetchJSON(`${API_BASE}/tool/render-status`);
   354|
   355|    // Also try /api/ivx/control-room/status for deploy history
   356|    let deployHistory: RenderDeployHistoryEntry[] = [];
   357|    try {
   358|      const deployHistoryRes = await fetchJSON(`${API_BASE}/api/ivx/developer-deploy/status`);
   359|      if (deployHistoryRes.ok) {
   360|        const rawHistory = deployHistoryRes.data.deployHistory as Array<Record<string, unknown>> | undefined;
   361|        if (rawHistory && Array.isArray(rawHistory)) {
   362|          deployHistory = rawHistory.map((d) => ({
   363|            deployId: (d.deployId as string) || (d.id as string) || '',
   364|            status: (d.status as string) || 'unknown',
   365|            commitSha: (d.commitSha as string) || (d.commit as string) || '',
   366|            timestamp: (d.timestamp as string) || (d.createdAt as string) || '',
   367|            durationMs: (d.durationMs as number) || (d.duration as number) || 0,
   368|            failureReason: d.failureReason as string | undefined,
   369|          }));
   370|        }
   371|      }
   372|    } catch {
   373|      // Deploy history is non-critical
   374|    }
   375|
   376|    const renderData = data.data as Record<string, unknown> | undefined;
   377|    const serviceName = (renderData?.serviceName as string) || 'ivx-holdings-platform';
   378|    const deployedSha = (data.commit as string)
   379|      || (renderData?.commit as string)
   380|      || (renderData?.deployedCommit as string)
   381|      || '';
   382|
   383|    const deployId = (data.deployId as string)
   384|      || (renderData?.deployId as string)
   385|      || (data.id as string)
   386|      || '';
   387|
   388|    // If we have a deploy history but no deployId, take the latest from history
   389|    const effectiveDeployId = deployId || (deployHistory[0]?.deployId ?? '');
   390|    const effectiveDeployStatus = (renderData?.serviceSuspended as boolean) ? 'suspended' : 'live';
   391|
   392|    const result: RenderEvidenceResult = {
   393|      status: ok ? 'ok' : 'fail',
   394|      service: serviceName,
   395|      deployId: effectiveDeployId,
   396|      deployStatus: (data.status as string) || effectiveDeployStatus,
   397|      deployedCommitSha: deployedSha,
   398|      deployTimestamp: (data.timestamp as string) || '',
   399|      commitMatch: false, // computed by orchestrator
   400|      deployHistory,
   401|      error: ok ? undefined : error,
   402|    };
   403|
   404|    pushEvent({
   405|      id: generateId(),
   406|      tool: 'Render',
   407|      phase: ok ? 'completed' : 'error',
   408|      message: ok
   409|        ? `Render service: ${serviceName}, deploy: ${effectiveDeployId || 'N/A'}, deploys in history: ${deployHistory.length}`
   410|        : `Render check failed: ${error}`,
   411|      timestamp: new Date().toISOString(),
   412|      detail: deployedSha,
   413|    });
   414|
   415|    return result;
   416|  } catch (err) {
   417|    const msg = parseError(err);
   418|    pushEvent({
   419|      id: generateId(),
   420|      tool: 'Render',
   421|      phase: 'error',
   422|      message: `Render check exception: ${msg}`,
   423|      timestamp: new Date().toISOString(),
   424|      detail: msg,
   425|    });
   426|    return {
   427|      status: 'fail',
   428|      service: 'ivx-holdings-platform',
   429|      deployId: '',
   430|      deployStatus: '',
   431|      deployedCommitSha: '',
   432|      deployTimestamp: '',
   433|      commitMatch: false,
   434|      deployHistory: [],
   435|      error: msg,
   436|    };
   437|  }
   438|}
