   440|/** Tests the /health endpoint with extended metrics. */
   441|async function checkHealthEvidence(
   442|  pushEvent: (event: StreamEvent) => void,
   443|): Promise<HealthEvidenceResult> {
   444|  pushEvent({
   445|    id: generateId(),
   446|    tool: 'Health',
   447|    phase: 'started',
   448|    message: 'Testing /health endpoint',
   449|    timestamp: new Date().toISOString(),
   450|  });
   451|
   452|  try {
   453|    const { ok, data, status, elapsedMs } = await fetchJSON(`${API_BASE}/health`);
   454|
   455|    if (!ok) {
   456|      pushEvent({
   457|        id: generateId(),
   458|        tool: 'Health',
   459|        phase: 'error',
   460|        message: `/health returned HTTP ${status}`,
   461|        timestamp: new Date().toISOString(),
   462|      });
   463|
   464|      // Load last failed check timestamp
   465|      const lastFailed = await loadLastFailedHealthCheck();
   466|      await saveLastFailedHealthCheck(new Date().toISOString());
   467|
   468|      return {
   469|        status: 'fail',
   470|        httpStatus: status,
   471|        responseBody: data,
   472|        responseTimeMs: elapsedMs,
   473|        liveCommitSha: '',
   474|        uptime: 'unknown',
   475|        apiErrorRate: 0,
   476|        lastFailedCheck: lastFailed,
   477|        error: `HTTP ${status}`,
   478|      };
   479|    }
   480|
   481|    const commit = (data.commit as string) || '';
   482|    const bootTime = data.bootTime as string | undefined;
   483|    const messageCount = data.messageCount as number | undefined;
   484|
   485|    // Derive uptime from boot time
   486|    let uptime = 'unknown';
   487|    if (bootTime) {
   488|      const boot = new Date(bootTime).getTime();
   489|      const now = Date.now();
   490|      const upMs = now - boot;
   491|      if (upMs > 0) {
   492|        const hours = Math.floor(upMs / 3600000);
   493|        const mins = Math.floor((upMs % 3600000) / 60000);
   494|        uptime = hours > 24
   495|          ? `${Math.floor(hours / 24)}d ${hours % 24}h`
   496|          : `${hours}h ${mins}m`;
   497|      }
   498|    }
   499|
   500|    // Clear last failed since this check succeeded
   501|    await clearLastFailedHealthCheck();
   502|
   503|    pushEvent({
   504|      id: generateId(),
   505|      tool: 'Health',
   506|      phase: 'completed',
   507|      message: `/health OK (${elapsedMs}ms), uptime: ${uptime}, commit: ${commit.slice(0, 8)}`,
   508|      timestamp: new Date().toISOString(),
   509|      detail: commit,
   510|    });
   511|
   512|    return {
   513|      status: 'ok',
   514|      httpStatus: status,
   515|      responseBody: data,
   516|      responseTimeMs: elapsedMs,
   517|      liveCommitSha: commit,
   518|      uptime,
   519|      apiErrorRate: 0, // Will be computed from error tracking if available
   520|      lastFailedCheck: await loadLastFailedHealthCheck(),
   521|    };
   522|  } catch (err) {
   523|    const msg = parseError(err);
   524|    await saveLastFailedHealthCheck(new Date().toISOString());
   525|    pushEvent({
   526|      id: generateId(),
   527|      tool: 'Health',
   528|      phase: 'error',
   529|      message: `Health check exception: ${msg}`,
   530|      timestamp: new Date().toISOString(),
   531|      detail: msg,
   532|    });
   533|    return {
   534|      status: 'fail',
   535|      httpStatus: 0,
   536|      responseBody: {},
   537|      responseTimeMs: 0,
   538|      liveCommitSha: '',
   539|      uptime: 'down',
   540|      apiErrorRate: 0,
   541|      lastFailedCheck: await loadLastFailedHealthCheck(),
   542|      error: msg,
   543|    };
   544|  }
   545|}
   546|
   547|// Health check failure tracking via AsyncStorage
   548|const LAST_FAILED_HEALTH_KEY = 'ivx_last_failed_health_check';
   549|
   550|async function loadLastFailedHealthCheck(): Promise<string | null> {
   551|  try {
   552|    return await AsyncStorage.getItem(LAST_FAILED_HEALTH_KEY);
   553|  } catch {
   554|    return null;
   555|  }
   556|}
