   570|/** Sends a test chat message, receives AI reply, and verifies full persistence. */
   571|async function checkChatEvidence(
   572|  pushEvent: (event: StreamEvent) => void,
   573|): Promise<ChatEvidenceResult> {
   574|  pushEvent({
   575|    id: generateId(),
   576|    tool: 'Chat',
   577|    phase: 'started',
   578|    message: 'Sending test chat message via /api/public/send-message',
   579|    timestamp: new Date().toISOString(),
   580|  });
   581|
   582|  try {
   583|    const testUsername = `evidence-bot-${Date.now()}`;
   584|    const testText = `IVX deployment evidence check — ${new Date().toISOString()}`;
   585|
   586|    // Phase 1: Send message
   587|    const sendResult = await fetchJSON(`${API_BASE}/api/public/send-message`, {
   588|      method: 'POST',
   589|      body: JSON.stringify({
   590|        roomId: 'main-room',
   591|        username: testUsername,
   592|        text: testText,
   593|        source: 'user',
   594|      }),
   595|    });
   596|
   597|    if (!sendResult.ok) {
   598|      pushEvent({
   599|        id: generateId(),
   600|        tool: 'Chat',
   601|        phase: 'error',
   602|        message: `Chat send failed: ${sendResult.error}`,
   603|        timestamp: new Date().toISOString(),
   604|        detail: sendResult.error,
   605|      });
   606|      return {
   607|        status: 'fail',
   608|        conversationId: 'main-room',
   609|        messageIds: [],
   610|        assistantReplied: false,
   611|        messageSaved: false,
   612|        messagePersistedAfterReload: false,
   613|        proofMessages: [],
   614|        error: sendResult.error,
   615|      };
   616|    }
   617|
   618|    const sendData = sendResult.data;
   619|    const assistantReplied = !!(sendData.assistantMessage || sendData.ai);
   620|    const userMsg = sendData.message as Record<string, unknown> | undefined;
   621|    const userMsgId = (userMsg?.id as string) || '';
   622|    const aiMsg = sendData.assistantMessage as Record<string, unknown> | undefined;
   623|    const assistantMsgId = (aiMsg?.id as string) || '';
   624|    const messageIds = [userMsgId, assistantMsgId].filter(Boolean);
   625|
   626|    const proofMessages: ChatProofMessage[] = [
   627|      {
   628|        id: userMsgId,
   629|        role: 'user',
   630|        text: testText.slice(0, 200),
   631|        timestamp: new Date().toISOString(),
   632|      },
   633|    ];
   634|    if (aiMsg) {
   635|      proofMessages.push({
   636|        id: assistantMsgId,
   637|        role: 'assistant',
   638|        text: ((aiMsg.text as string) || (aiMsg.content as string) || '').slice(0, 200),
   639|        timestamp: new Date().toISOString(),
   640|      });
   641|    }
   642|
   643|    // Phase 2: Verify immediate persistence (message saved)
   644|    let messageSaved = false;
   645|    try {
   646|      const msgsResult = await fetchJSON(
   647|        `${API_BASE}/api/public/messages?roomId=main-room&limit=10`,
   648|      );
   649|      if (msgsResult.ok) {
   650|        const messages = (msgsResult.data.messages as Array<Record<string, unknown>>) || [];
   651|        messageSaved = messages.some((m) => m.id === userMsgId);
   652|      }
   653|    } catch {
   654|      // Non-fatal
   655|    }
   656|
   657|    // Phase 3: Verify persistence after reload (re-fetch with a small delay)
